import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  DateRangeFilter,
  Pagination,
  SearchTextInput,
  Select,
  StatusBadge,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherListFilterState } from '../../../hooks/useVoucherListFilterState';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { lsxPageLabels as labels } from '../../../constants/lsxPageLabels';
import { sxService } from '../../../services/sx/sxService';
import type { ProductionOrderDto, ProductionOrderStatus } from '../../../services/sx/models';
import { formatDateLocal, formatNumber, formatPercent } from '../../../utils/format';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { openListRowMenu } from '../../../utils/openListRowMenu';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../../../components/voucher-list';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { useMesLsxPermissions } from '../../../hooks/useMesPermissions';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-lsx';
const PAGE_ID = 'sx-lsx';
const CATALOG_KIND = LIST_UI_SCHEMA_KIND.productionOrder;
const showSchemaConfig = true;
const PAGE_SIZE = 20;

const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: 'Draft', label: 'Nháp' },
  { value: 'Released', label: 'Đã phát lệnh' },
  { value: 'InProgress', label: 'Đang SX' },
  { value: 'Completed', label: 'Hoàn thành' },
  { value: 'Closed', label: 'Đóng' },
];

const LsxListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const perms = useMesLsxPermissions();
  const [reloadKey, setReloadKey] = useState(0);
  const [items, setItems] = useState<ProductionOrderDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [actionId, setActionId] = useState<string | null>(null);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: ProductionOrderDto } | null>(
    null,
  );
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);

  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(LIST_FILTER_SCOPE.lsx);

  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useErpListSelection({
    rows: items,
    totalCount,
    page,
    pageSize: PAGE_SIZE,
    getRowId: r => r.id,
  });

  const activeRow = selection.activeRow;

  const refresh = useCallback(() => {
    selection.clearActiveRow();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = useCallback(() => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
      selection.clearActiveRow();
      setReloadKey(k => k + 1);
    });
  }, [pulseSearch, searchDraft, setSearch, setPage, selection]);

  const navigateToRow = useCallback(
    (id: string, startInEditMode?: boolean) => {
      navigate(`/sx/lsx/${id}`, {
        state: startInEditMode ? { startInEditMode: true } : undefined,
      });
    },
    [navigate],
  );

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getProductionOrders({
          status: status || undefined,
          fromDate: fromDate || undefined,
          toDate: toDate || undefined,
          searchText: search || undefined,
          page,
          pageSize: PAGE_SIZE,
        })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [initialized, status, fromDate, toDate, page, search, reloadKey, dispatch]);

  const handleRelease = async (id: string) => {
    setActionId(id);
    try {
      await sxService.releaseProductionOrder(id);
      dispatchAppToast(dispatch, { message: labels.releaseSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.releaseError),
        type: 'error',
      });
    } finally {
      setActionId(null);
    }
  };

  const handleComplete = async (id: string) => {
    setActionId(id);
    try {
      await sxService.completeProductionOrder(id);
      dispatchAppToast(dispatch, { message: labels.completeSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.completeError),
        type: 'error',
      });
    } finally {
      setActionId(null);
    }
  };

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      if (action === 'view') navigateToRow(row.id);
      if (action === 'edit') navigateToRow(row.id, true);
    },
    [rowMenu?.row, navigateToRow],
  );

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canView: Boolean(activeRow) && perms.canRead,
      onView: () => activeRow && navigateToRow(activeRow.id),
      canEdit: Boolean(activeRow) && perms.canUpdate,
      onEdit: () => activeRow && navigateToRow(activeRow.id, true),
      canCreate: perms.canCreate,
      onCreate: () => navigate('/sx/lsx/them'),
      ...(showSchemaConfig ? { onEditConfig: () => setShowSchemaEditor(true) } : {}),
    }),
    [refresh, activeRow, navigate, navigateToRow, perms],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            placeholder={labels.searchPlaceholder}
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
              setReloadKey(k => k + 1);
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label="Trạng thái"
            value={status}
            onChange={e => {
              setStatus(e.target.value);
              resetPage();
              setReloadKey(k => k + 1);
            }}
            options={STATUS_OPTIONS}
            fullWidth
          />
        ),
      },
    ],
    [
      searchDraft,
      handleSearch,
      fromDate,
      toDate,
      datePreset,
      status,
      applyDateRange,
      resetPage,
      setStatus,
    ],
  );

  const listBody =
    !showTableLoading && items.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>Số LSX</th>
              <th>Ngày</th>
              <th>Sản phẩm</th>
              <th className={erp.colRight}>SL đặt</th>
              <th className={erp.colRight}>Hoàn thành</th>
              <th>Hạn</th>
              <th>Trạng thái</th>
              <th className={erp.colActions} />
            </tr>
          </thead>
          <tbody>
            {items.map(r => {
              const pct = formatPercent(r.completedQty, r.orderQty);
              return (
                <tr
                  key={r.id}
                  data-testid={`${TEST_ID}-row-${r.id}`}
                  className={selection.activeRow?.id === r.id ? erp.rowSelected : undefined}
                  onDoubleClick={() => navigateToRow(r.id)}
                  onContextMenu={e =>
                    openListRowMenu(e, r, selection.selectActiveRow, setRowMenu)
                  }
                  onClick={e => {
                    if (e.ctrlKey || e.metaKey) {
                      openListRowMenu(e, r, selection.selectActiveRow, setRowMenu);
                    }
                  }}
                >
                  <td>
                    <button
                      type="button"
                      className={erp.codeLink}
                      onClick={() => navigateToRow(r.id)}
                    >
                      <code>{r.code}</code>
                    </button>
                  </td>
                  <td>{formatDateLocal(r.orderDate)}</td>
                  <td>{r.productName ?? r.productCode}</td>
                  <td className={erp.colRight}>{formatNumber(r.orderQty)}</td>
                  <td className={erp.colRight}>
                    {formatNumber(r.completedQty)}{' '}
                    <span className={erp.tagDefault}>({pct}%)</span>
                  </td>
                  <td>{formatDateLocal(r.plannedEndDate)}</td>
                  <td>
                    <StatusBadge status={r.status as ProductionOrderStatus} />
                  </td>
                  <td className={erp.colActions}>
                    {perms.canUpdate && (
                      <button
                        type="button"
                        className={erp.actionBtn}
                        onClick={() => navigateToRow(r.id, true)}
                        title="Sửa"
                      >
                        <i className="fas fa-edit" />
                      </button>
                    )}
                    {r.status === 'Draft' && perms.canRelease && (
                      <button
                        type="button"
                        className={erp.actionBtn}
                        disabled={actionId === r.id}
                        onClick={() => handleRelease(r.id)}
                        title="Phát lệnh"
                      >
                        <i className="fas fa-play" />
                      </button>
                    )}
                    {(r.status === 'Released' || r.status === 'InProgress') &&
                      perms.canComplete && (
                      <button
                        type="button"
                        className={erp.actionBtn}
                        disabled={actionId === r.id}
                        onClick={() => handleComplete(r.id)}
                        title="Hoàn thành"
                      >
                        <i className="fas fa-check" />
                      </button>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-kind={CATALOG_KIND}
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.listTitle,
          titleIconClass: 'fas fa-industry',
          pageId: PAGE_ID,
        }}
        voucherToolbar={voucherToolbar}
        listTitle={labels.listSubtitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={
          totalCount > 0 ? (
            <div className={erp.paginationRow}>
              <span className={erp.totalCount}>Tổng: {totalCount} lệnh</span>
              <Pagination
                currentPage={page}
                totalPages={Math.ceil(totalCount / PAGE_SIZE)}
                totalCount={totalCount}
                pageSize={PAGE_SIZE}
                onPageChange={p => {
                  setPage(p);
                  selection.clearActiveRow();
                }}
              />
            </div>
          ) : undefined
        }
        modals={
          <>
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showView={perms.canRead}
              showEdit={perms.canUpdate}
            />
            {showSchemaConfig ? (
              <ListUiSchemaEditorModal
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                isOpen={showSchemaEditor}
                onClose={() => setShowSchemaEditor(false)}
                onSaved={() => refresh()}
                sampleRow={items[0] as unknown as Record<string, unknown>}
              />
            ) : null}
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default LsxListPage;
